class Solution {
    public String reverseParentheses(String s) {
        while (s.contains("(")) {
            int start = s.lastIndexOf('(');
            int end = s.indexOf(')', start);
            String sub = new StringBuilder(s.substring(start + 1, end)).reverse().toString();
            s = s.substring(0, start) + sub + s.substring(end + 1);
        }
        return s;
    }
}
